function postProcess(tokens: Token[]): Token[] {
  return detectArraySubscripts(promotePipeClauses(combineParameterizedTypes(tokens)));
}

const pipeClauseKeywords = new Set([
  'WHERE',
  'SELECT',
  'ORDER BY',
  'AGGREGATE',
  'EXTEND',
  'SET',
  'DROP',
  'LIMIT',
  'JOIN',
  'LEFT JOIN',
  'LEFT OUTER JOIN',
  'RIGHT JOIN',
  'RIGHT OUTER JOIN',
  'FULL JOIN',
  'FULL OUTER JOIN',
  'INNER JOIN',
  'CROSS JOIN',
  'AS',
]);

function promotePipeClauses(tokens: Token[]): Token[] {
  let expectingClause = false;
  let aggregateClause = false;

  return tokens.map(token => {
    if (token.type === TokenType.PIPE_OPERATOR) {
      expectingClause = true;
      aggregateClause = false;
      return token;
    }

    if (expectingClause && (token.type === TokenType.BLOCK_COMMENT || token.type === TokenType.LINE_COMMENT)) {
      return token;
    }

    if (expectingClause) {
      expectingClause = false;
      aggregateClause = token.text === 'AGGREGATE';
      return pipeClauseKeywords.has(token.text) ? { ...token, type: TokenType.PIPE_CLAUSE } : token;
    }

    if (aggregateClause && token.text === 'GROUP BY' && token.type === TokenType.RESERVED_CLAUSE) {
      return { ...token, type: TokenType.PIPE_GROUP_BY };
    }

    return token;
  });
}

